 1	import * as React from 'react';
 2	import { EnrollApplicationButton } from '@odf/mco/components/protected-applications/components';
 3	import { gettingStartedDRDocs } from '@odf/mco/constants';
 4	import { render, screen } from '@testing-library/react';
 5	import userEvent from '@testing-library/user-event';
 6	import { GettingStartedCard } from './getting-started-card';
 7	
 8	const setIsOpen = jest.fn(() => null);
 9	const navigate = jest.fn(() => null);
10	
11	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
12	  ...jest.requireActual('@openshift-console/dynamic-plugin-sdk'),
13	  useFlag: jest.fn(() => true),
14	  useK8sWatchResource: jest.fn(() => [['policy1', 'policy2'], true, '']),
15	  useUserSettings: jest.fn(() => [true, setIsOpen]),
16	  AlertSeverity: { Critical: 'critical' },
17	}));
18	
19	jest.mock('react-router-dom-v5-compat', () => ({
20	  ...jest.requireActual('react-router-dom-v5-compat'),
21	  useNavigate: () => navigate,
22	}));
23	
24	jest.mock('@odf/shared/hooks', () => ({
25	  ...jest.requireActual('@odf/shared/hooks'),
26	  DOC_VERSION: '1.2',
27	}));
28	
29	jest.mock('@odf/mco/components/protected-applications/components', () => ({
30	  ...jest.requireActual(
31	    '@odf/mco/components/protected-applications/components'
32	  ),
33	  EnrollApplicationButton: jest.fn(() => null),
34	}));
35	
36	describe('Test getting started card (GettingStartedCard)', () => {
37	  afterEach(() => jest.clearAllMocks());
38	
39	  it('Renders card with all the steps and their details', async () => {
40	    const user = userEvent.setup();
41	    render(<GettingStartedCard />);
42	
43	    // header -- title
44	    expect(screen.getByText('Create policy')).toBeInTheDocument();
45	    expect(screen.getByText('Enroll applications')).toBeInTheDocument();
46	    expect(
47	      screen.getByText('Monitoring resources (optional)')
48	    ).toBeInTheDocument();
49	
50	    // body -- doc link
51	    expect(screen.getByText('See documentation')).toHaveAttribute(
52	      'href',
53	      gettingStartedDRDocs('1.2').CREATE_POLICY
54	    );
55	    expect(screen.getByText('Steps to enable monitoring')).toHaveAttribute(
56	      'href',
57	      gettingStartedDRDocs('1.2').ENABLE_MONITORING
58	    );
59	
60	    // footer -- button
61	    const policyButton = screen.getByRole('button', {
62	      name: 'Create a disaster recovery policy',
63	    });
64	    expect(policyButton).toBeInTheDocument();
65	    await user.click(policyButton);
66	    expect(navigate).toHaveBeenCalledTimes(1);
67	
68	    const viewPolicyButton = screen.getByRole('button', {
69	      name: 'View policies',
70	    });
71	    expect(viewPolicyButton).toBeInTheDocument();
72	    await user.click(viewPolicyButton);
73	    expect(navigate).toHaveBeenCalledTimes(2); // called once before via "policyButton" click
74	
75	    expect(EnrollApplicationButton).toHaveBeenCalledTimes(1);
76	  });
77	});

