 1	import * as React from 'react';
 2	import {
 3	  ACM_OBSERVABILITY_FLAG,
 4	  GETTING_STARTED_USER_SETTINGS_KEY_OVERVIEW_DASHBOARD,
 5	} from '@odf/mco/constants';
 6	import { GettingStartedExpandableGrid } from '@odf/shared/getting-started-grid';
 7	import { DOC_VERSION as mcoDocVersion } from '@odf/shared/hooks';
 8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 9	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
10	// ToDo (Sanjal): Update sdk (stable & internal) version and remove these comments
11	// @ts-ignore
12	import { useUserSettings } from '@openshift-console/dynamic-plugin-sdk';
13	import { HeaderSection, BodySection, gettingStartedSteps } from './helper';
14	
15	export const GettingStartedCard: React.FC = () => {
16	  const { t } = useCustomTranslation();
17	
18	  const [isGettingStartedSectionOpen, setIsGettingStartedSectionOpen] =
19	    useUserSettings<boolean>(
20	      GETTING_STARTED_USER_SETTINGS_KEY_OVERVIEW_DASHBOARD,
21	      true
22	    );
23	  const isMonitoringEnabled = useFlag(ACM_OBSERVABILITY_FLAG);
24	
25	  return (
26	    <GettingStartedExpandableGrid
27	      isOpen={isGettingStartedSectionOpen}
28	      setIsOpen={setIsGettingStartedSectionOpen}
29	      title={t('Getting started with disaster recovery')}
30	      hideExpandable={!isMonitoringEnabled}
31	    >
32	      <div className="pf-v6-u-display-flex pf-v6-u-flex-direction-column pf-v6-u-flex-direction-row-on-lg pf-v6-u-justify-content-space-between">
33	        {gettingStartedSteps(t, mcoDocVersion).map((step) => {
34	          const stepCount = step.stepCount;
35	          const FooterComponent = step.FooterComponent;
36	          return (
37	            <div
38	              className="pf-v6-u-display-flex pf-v6-u-flex-direction-column pf-v6-u-p-sm pf-v6-u-w-25-on-lg"
39	              key={stepCount}
40	            >
41	              <HeaderSection
42	                stepCount={stepCount}
43	                heading={step.heading}
44	                key={`${stepCount}-header`}
45	              />
46	              <BodySection
47	                message={step.message}
48	                docLink={step.docLink}
49	                docText={step.docText}
50	                key={`${stepCount}-body`}
51	              />
52	              {!!FooterComponent && (
53	                <FooterComponent key={`${stepCount}-footer`} />
54	              )}
55	            </div>
56	          );
57	        })}
58	      </div>
59	    </GettingStartedExpandableGrid>
60	  );
61	};

