  1	import * as React from 'react';
  2	import { EnrollApplicationButton } from '@odf/mco/components/protected-applications/components';
  3	import { gettingStartedDRDocs, DR_BASE_ROUTE } from '@odf/mco/constants';
  4	import { getDRPolicyResourceObj } from '@odf/mco/hooks';
  5	import { DRPolicyKind } from '@odf/mco/types';
  6	import { DRPolicyModel } from '@odf/shared';
  7	import { StepsCountBadge } from '@odf/shared/badges';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { referenceForModel, ViewDocumentation } from '@odf/shared/utils';
 10	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 11	import { Trans, TFunction } from 'react-i18next';
 12	import { useNavigate } from 'react-router-dom-v5-compat';
 13	import { Button, ButtonVariant } from '@patternfly/react-core';
 14	import './getting-started-card.scss';
 15	
 16	const PolicyFooterSection: React.FC = () => {
 17	  const { t } = useCustomTranslation();
 18	
 19	  const navigate = useNavigate();
 20	  const [drPolicies, drPoliciesLoaded, drPoliciesLoadError] =
 21	    useK8sWatchResource<DRPolicyKind[]>(getDRPolicyResourceObj());
 22	
 23	  const loadedWOError = drPoliciesLoaded && !drPoliciesLoadError;
 24	  const policyCount = drPolicies?.length;
 25	  return (
 26	    <div className="pf-v6-u-mt-md">
 27	      <Button
 28	        variant={ButtonVariant.secondary}
 29	        className="pf-v6-u-mb-xs mco-policy--footer"
 30	        onClick={() =>
 31	          navigate(
 32	            `${DR_BASE_ROUTE}/policies/${referenceForModel(DRPolicyModel)}/~new`
 33	          )
 34	        }
 35	      >
 36	        {t('Create a disaster recovery policy')}
 37	      </Button>
 38	      {loadedWOError &&
 39	        (!policyCount ? (
 40	          <p className="text-muted">{t('No disaster recovery policies.')}</p>
 41	        ) : (
 42	          // "toString" is needed otherwise RTL gives "Objects are not valid as a React child" error
 43	          <Trans t={t}>
 44	            <p className="text-muted">
 45	              You have {policyCount.toString()} disaster recovery policies.{' '}
 46	              <Button
 47	                variant={ButtonVariant.link}
 48	                onClick={() => navigate(`${DR_BASE_ROUTE}/policies`)}
 49	                isInline
 50	              >
 51	                {t('View policies')}
 52	              </Button>
 53	            </p>
 54	          </Trans>
 55	        ))}
 56	    </div>
 57	  );
 58	};
 59	
 60	const EnrollAppFooterSection: React.FC = () => {
 61	  const { t } = useCustomTranslation();
 62	
 63	  return (
 64	    <div className="mco-enroll-app--footer pf-v6-u-mt-md">
 65	      <EnrollApplicationButton toggleVariant="secondary" isNoDataMessage />
 66	      <Trans t={t}>
 67	        <p className="text-muted pf-v6-u-mt-sm">
 68	          View enrolled apps under{' '}
 69	          <span className="pf-v6-u-font-weight-bold">
 70	            Protected applications
 71	          </span>
 72	          .
 73	        </p>
 74	      </Trans>
 75	    </div>
 76	  );
 77	};
 78	
 79	export const HeaderSection: React.FC<{
 80	  stepCount: number;
 81	  heading: string;
 82	}> = ({ stepCount, heading }) => {
 83	  return (
 84	    <p className="pf-v6-u-mb-md">
 85	      <span className="pf-v6-u-mr-sm">
 86	        <StepsCountBadge stepCount={stepCount} />
 87	      </span>{' '}
 88	      <span className="pf-v6-u-font-weight-bold">{heading}</span>
 89	    </p>
 90	  );
 91	};
 92	
 93	export const BodySection: React.FC<{
 94	  message: string;
 95	  docLink?: string;
 96	  docText?: string;
 97	}> = ({ message, docLink, docText }) => {
 98	  return (
 99	    <>
100	      {message}
101	      <ViewDocumentation doclink={docLink} text={docText} padding="15px 0px" />
102	    </>
103	  );
104	};
105	
106	type GettingStartedSteps = {
107	  // header
108	  stepCount: number;
109	  heading: string;
110	  // body
111	  message: string;
112	  docLink?: string;
113	  docText?: string;
114	  // footer
115	  FooterComponent?: React.FC;
116	}[];
117	
118	export const gettingStartedSteps = (
119	  t: TFunction<string>,
120	  mcoDocVersion: string
121	): GettingStartedSteps => [
122	  {
123	    // header
124	    stepCount: 1,
125	    heading: t('Create policy'),
126	    // body
127	    message: t(
128	      'Decide how often your data should be replicated and where it should be stored, either regionally or within your local area, to ensure a quick recovery in case of a disaster.'
129	    ),
130	    docLink: gettingStartedDRDocs(mcoDocVersion).CREATE_POLICY,
131	    docText: t('See documentation'),
132	    // footer
133	    FooterComponent: PolicyFooterSection,
134	  },
135	  {
136	    // header
137	    stepCount: 2,
138	    heading: t('Enroll applications'),
139	    // body
140	    message: t(
141	      'Add disaster recovery protection to your application to boost resilience and minimise downtime.'
142	    ),
143	    // footer
144	    FooterComponent: EnrollAppFooterSection,
145	  },
146	  {
147	    // header
148	    stepCount: 3,
149	    heading: t('Monitoring resources (optional)'),
150	    // body
151	    message: t(
152	      'Monitoring offers an enhanced perspective on disaster recovery, providing a more optimized view of the ongoing replication and status of volumes at both cluster and application levels.'
153	    ),
154	    docLink: gettingStartedDRDocs(mcoDocVersion).ENABLE_MONITORING,
155	    docText: t('Steps to enable monitoring'),
156	  },
157	];

